








































































































import _ from 'lodash';
import {
  Component,
  Prop,
  Vue,
} from 'vue-property-decorator';
import { CARD } from '@/interface/card';
import CardPopover from '@/components/CardPopover.vue';
import {
  RenWuPicker,
  FaBaoPicker,
} from '@/data/pickerData';
import { choosePopover, countAll } from '@/utils/countUtil';
import { Action, State } from 'vuex-class';
import { type } from '@/data/constans';

@Component({
  components: {
  CardPopover
  }
  })
export default class CardChoose extends Vue {
    @Prop() private num!: number
    @Action private selectCard!: (user: any) => void
    @State private currentData!: Array<Array<object>>
    private renwu!: Array < object >
    private fabao!: Array < object >
    private rwValue!: any
    private fbValue!: string
    private ren1!: number
    private ren2!: number
    private ren3!: number
    private fa1!: number
    private fa2!: number
    private fa3!: number
    private renwuPopItem!: object
    private fabaoPopItem!: object
    private $message!: any
    private data() {
      return {
        renwu: RenWuPicker,
        fabao: FaBaoPicker,
        rwValue: [],
        fbValue: '',
        ren1: 1,
        ren2: 0,
        ren3: 0,
        fa1: 1,
        fa2: 0,
        fa3: 0,
        renwuPopItem: {},
        fabaoPopItem: {},
      };
    }
    private syncrenwuPopItem() {
      this.renwuPopItem = choosePopover({
        name: (this.rwValue && this.rwValue[1]) || '',
        levelXiu: this.ren1,
        levelDu: this.ren2,
        levelJu: this.ren3,
      });
      countAll(this.currentData);
    }
    private syncfabaoPopItem() {
      this.fabaoPopItem = choosePopover({
        name: this.fbValue,
        levelXiu: this.fa1,
        levelDu: this.fa2,
        levelJu: this.fa3,
      });
      countAll(this.currentData);
    }
    private renwuChange(val: Array<string>) {
      const current = this.currentData.reduce((a, b) => a.concat(b), []);
      const nameList: Array<string> = [];
      _.forEach(current, (item: any) => nameList.push(item.name));
      if (_.indexOf(nameList, val[1]) > -1) {
        this.rwValue = [];
        this.$message.error('不能重复选择！');
        return;
      }
      this.selectCard({
        num: this.num,
        type: type.ren_wu,
        character: val[0],
        name: val[1],
        levelXiu: this.ren1,
        levelDu: this.ren2,
        levelJu: this.ren3,
      });
      this.syncrenwuPopItem();
    }
    private fabaoChange(val: string) {
      this.selectCard({
        num: this.num,
        type: type.fa_bao,
        name: val,
        levelXiu: this.fa1,
        levelDu: this.fa2,
        levelJu: this.fa3,
      });
      this.syncfabaoPopItem();
    }

    private renwulevelChange(val: number) {
      if (this.ren3 > 0) {
        this.ren2 = 12;
      }
      if (_.isEmpty(this.rwValue)) {
        this.$message.error('请先选择阵灵！');
        return;
      }
      this.selectCard({
        num: this.num,
        type: type.ren_wu,
        character: this.rwValue[0],
        name: this.rwValue[1],
        levelXiu: this.ren1,
        levelDu: this.ren2,
        levelJu: this.ren3,
      });
      this.syncrenwuPopItem();
    }
    private fabaolevelChange(val: number) {
      if (this.fa3 > 0) {
        this.fa2 = 12;
      }
      if (_.isEmpty(this.fbValue)) {
        this.$message.error('请先选择阵灵！');
        return;
      }
      this.selectCard({
        num: this.num,
        type: type.fa_bao,
        name: this.fbValue,
        levelXiu: this.fa1,
        levelDu: this.fa2,
        levelJu: this.fa3,
      });
      this.syncfabaoPopItem();
    }


    private handleChange() {

    }
    private formatTooltip(val: number) {
      return val / 12;
    }
}
